/**
 * @brief 初始化init线程，进入scheduler后调度执行
 */
extern proc_t *initproc;
void init_process()
{
    struct proc *p = allocproc();
    initproc = p;
    p->state = RUNNABLE;
    uint32 len = sizeof(init_code);
    printf("user len:%p\n", len);
    LOG("user init_code: %p\n", init_code);
    uvminit(p, init_code, len);
    p->virt_addr = 0;
    p->sz = len;
    p->sz = PGROUNDUP(p->sz);
    p->cwd.fs = get_fs_by_type(EXT4);
    uint64 sp = get_proc_sp(p);
    strcpy(p->cwd.path, "/");
    hsai_set_trapframe_epc(p->trapframe, 0);
    hsai_set_trapframe_user_sp(p->trapframe, sp);
    copytrapframe(p->current_thread->trapframe, p->trapframe);
    p->current_thread->state = t_RUNNABLE; ///< 设置主线程状态为可运行
    release(&p->lock);                     ///< 释放在allocproc()中加的锁
}

extern void service_process_loop();

/*内核服务进程，其实不需要用户态的资源*/
void service_process_init()
{
#if SERVICE_PROCESS_CONFIG
    struct proc *p = allocproc();
    p->state = RUNNABLE;
    p->virt_addr = 0;
    p->sz = 0;
    p->cwd.fs = get_fs_by_type(EXT4);
    // uint64 sp =  get_proc_sp(p); //还是获取一个占位置，毕竟服务进程占用了pid。不获取了，应该没问题吧
    // hsai_set_trapframe_user_sp(p->trapframe, sp);
    strcpy(p->cwd.path, "/");
    p->context.ra = (uint64)service_process_loop;
    p->current_thread->context.ra = (uint64)service_process_loop;
    p->current_thread->state = t_RUNNABLE; ///< 设置主线程状态为可运行
    release(&p->lock);                     ///< 释放在allocproc()中加的锁
#endif
}

