// initialize the proc table at boot time.
void proc_init(void)
{
    struct proc *p;
    initlock(&pid_lock, "nextpid");
    initlock(&parent_lock, "parent_lock");

    /* 初始化UTS命名空间系统 */
    init_uts_namespaces();

    for (p = pool; p < &pool[NPROC]; p++)
    {
        initlock(&p->lock, "proc");
        p->state = UNUSED;
        p->exit_state = 0;
        p->kstack = KSTACK((int)(p - pool));
        // p->trapframe = (struct trapframe *)trapframe[p - pool];
        p->trapframe = 0;
        p->parent = 0;
        p->ktime = 0;
        p->utime = 0;
        // 初始化文件描述符数组
        for (int i = 0; i < NOFILE; i++)
            p->ofile[i] = 0;
    }
}

int allocpid(void)
{
    static int PID = 1;
    acquire(&pid_lock);
    int pid = PID++;
    release(&pid_lock);
    if (pid > PID_MAX)
    {
        return -1;
    }
    return pid;
}

struct proc *getproc(int pid)
{
    struct proc *p;
    for (p = pool; p < &pool[NPROC]; p++)
    {
        if (p->pid == pid)
        {
            return p;
        }
    }
    return NULL;
}

