/**
 * @brief 递归释放多级页表及其占用的物理内存
 *
 * @param pt
 */
void freewalk(pgtbl_t pt)
{
    /* 遍历当前页表的所有512个PTE */
    for (int i = 0; i < 512; i++)
    {
        pte_t pte = pt[i];
        if ((pte & PTE_V) && PTE_FLAGS(pte) == PTE_V) ///< 有效且指向下级页表的PTE
        {
            uint64 child = (PTE2PA(pte) | dmwin_win0);
            freewalk((pgtbl_t)child);
            pt[i] = 0;
        }
        else if (pte & PTE_V) ///< 未释放的叶级PTE
        {
            // panic("freewalk: leaf");
            continue;
        }
    }
    pmem_free_pages(pt, 1);
}

