static struct file *find_file(const char *path)
{
    extern struct proc pool[NPROC];
    struct proc *p;
    for (int i = 0; i < NPROC; i++)
    {
        p = &pool[i];
        for (int j = 0; j < NOFILE; j++)
        {
            if (p->ofile[j] && p->ofile[j]->f_count > 0 &&
                !strcmp(p->ofile[j]->f_path, path))
                return p->ofile[j];
        }
    }
    return NULL;
}
