int generate_proc_interrupts_content(char *buf, int size)
{
    if (!buf || size <= 0)
        return -1;

    acquire(&interrupt_lock);

    int written = 0;
    int first = 1;

    // 遍历所有中断号，只输出有计数的中断
    for (int i = 0; i < 256; i++)
    {
        if (interrupt_counts[i] > 0)
        {
            int len = snprintf(buf + written, size - written, "%s%d: %*lu\n",
                               first ? "" : "", i, 8, interrupt_counts[i]);
            if (len >= size - written)
            {
                // 缓冲区不够，停止写入
                break;
            }
            written += len;
            first = 0;
        }
    }

    release(&interrupt_lock);
    return written;
}

