 * @brief slab分配，只处理小于一个页的。认为0<size<=4096
 */
void *slab_alloc(uint64 size)
{
    struct kmem_cache *s;
    /*处理size*/
    uint32 aligned_size = __slab_size(size);

    // 如果size超过slab支持的最大大小，直接使用页分配器
    if (aligned_size == 0 || aligned_size > 1024)
