    // else printf("读请求！");
    // printf("准备发送请求到virtio\n");
    *R(VIRTIO_MMIO_QUEUE_NOTIFY) = 0; // value is queue number

    // Wait for virtio_disk_intr() to say request has finished.
    while (b->disk == 1)
    {
        // printf("wait");
        sleep_on_chan(b, &disk.vdisk_lock);
    }
    // printf("中断返回响应!\n");

    disk.info[idx[0]].b = 0;
    free_chain(idx[0]);

    release(&disk.vdisk_lock);

    return 0;
}

