    while (pos) {
        pos += pci_base;
        pci_config_read(&cap, sizeof(cap), pos);

        if (cap.cap_vndr != PCI_CAP_ID_VNDR) {         // PCI_CAP_ID_VNDR vendor-specific Cap
			// printf("[%2llx] skipping non VNDR cap id: %02x\n",
				    // pos, cap.cap_vndr);
