        pmem_init();            // 初始化物理内存
        vmem_init();            // 初始化虚拟内存
        shm_init();             // 初始化共享内存
        slab_init();            // 初始化 Slab 分配器

        hsai_trap_init();       // 初始化中断和异常

        // 初始化设备驱动
        #if defined RISCV
        plicinit();
        plicinithart();
        virtio_disk_init();
        #else
        virtio_probe();
        la_virtio_disk_init();
        #endif

        // 初始化文件系统
