#### 3.2.2 进程创建与调度

**进程分配** (`allocproc`)：
```c
struct proc *allocproc(void)
{
    struct proc *p;
    for (p = pool; p < &pool[NPROC]; p++) {
        acquire(&p->lock);
        if (p->state == UNUSED) {
            goto found;
        }
        release(&p->lock);
    }
    return 0;

found:
    p->pid = allocpid();
    p->state = USED;
    p->trapframe = pmem_alloc_pages(1);
    p->pagetable = proc_pagetable(p);

    // 初始化资源限制
    p->rlimits[RLIMIT_STACK] = (struct rlimit){8 * 1024 * 1024, RLIM_INFINITY};
    p->rlimits[RLIMIT_NOFILE] = (struct rlimit){NOFILE, NOFILE};
    // ... 其他限制

    // 初始化线程
    thread_t *t = alloc_thread();
    t->p = p;
    t->tid = p->pid;
    list_push_back(&p->thread_queue, &t->elem);
    p->current_thread = t;

    return p;
}
```

**调度器** (`scheduler`)：
```c
void scheduler(void)
{
    struct proc *p;
    struct cpu *c = mycpu();

    for (;;) {
        // 遍历进程池寻找可运行进程
        for (p = pool; p < &pool[NPROC]; p++) {
            acquire(&p->lock);
            if (p->state == RUNNABLE) {
                // 检查线程状态
                thread_t *t = p->current_thread;
                if (t->state == t_RUNNABLE) {
                    // 切换到进程
                    c->proc = p;
                    p->state = RUNNING;
                    swtch(&c->context, &p->context);
                    c->proc = 0;
                }
            }
            release(&p->lock);
        }
    }
}
```

**关键特性**：
- 静态进程池（`NPROC` 个进程槽位）
- 支持进程组、会话管理
- 完整的资源限制（rlimit）支持
- 支持 UTS 命名空间隔离

