    # ... 恢复所有寄存器

    addi sp, sp, 256
    sret
```

#### 3.12.2 中断分发

```c
void kerneltrap()
{
    struct trapframe *trapframe = myproc()->trapframe;

    #if defined RISCV
    uint64 scause = r_scause();
    uint64 stval = r_stval();

    if (scause & 0x8000000000000000L) {
        // 中断
        int irq = devintr();
        if (irq == 0) {
            // 未知中断
        }
    } else {
        // 异常
        switch (scause) {
        case 8:  // 用户态系统调用
            syscall(trapframe);
            break;
        case 13: // 加载页错误
        case 15: // 存储页错误
            pagefault_handler(stval);
            break;
        default:
            panic("unknown exception");
        }
    }
    #else
    // LoongArch 处理
    uint64 estat = r_csr_estat();
    uint64 era = r_csr_era();

    if (estat & CSR_ESTAT_IS_11) {
        // 定时器中断
        timerintr();
    } else if (estat & CSR_ESTAT_IS_10) {
        // 外部中断
        devintr();
    } else {
        // 异常
        int exccode = (estat >> 16) & 0x1fff;
        switch (exccode) {
        case EXCCODE_SYS:
            syscall(trapframe);
            break;
        case EXCCODE_TLBR:
            pagefault_handler(r_csr_badvaddr());
            break;
        }
    }
    #endif
}
```

